    20	use serde::{Deserialize, Serialize};
    21	
    22	/// Base ID for EVE Frontier solar systems.
    23	/// All system IDs are encoded as offsets from this value.
    24	pub const BASE_SYSTEM_ID: u32 = 30_000_000;
    25	
    26	/// Current fmap format version.
    27	pub const FMAP_VERSION: u8 = 1;
    28	
    29	/// Header size in bytes (version + k + count).
    30	pub const FMAP_HEADER_SIZE: usize = 4;
    31	
    32	/// Maximum bit width for system ID offsets.
    33	pub const MAX_BIT_WIDTH: u8 = 30;
