    38	/// Waypoint type for fmap route encoding.
    39	///
    40	/// Values correspond to the frontier-reapers/starmap specification.
    41	#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
    42	#[repr(u8)]
    43	pub enum WaypointType {
    44	    /// Route starting point (Type 0)
    45	    Start = 0,
    46	    /// Spatial jump without gate (Type 1)
    47	    Jump = 1,
    48	    /// Jump via NPC-controlled gate (Type 2)
    49	    NpcGate = 2,
    50	    /// Jump via player-deployed smart gate (Type 3)
    51	    SmartGate = 3,
    52	    /// Final destination marker (Type 4)
    53	    SetDestination = 4,
    54	}
    55	
    56	impl WaypointType {
    57	    /// Create from numeric value.
    58	    pub fn from_u8(value: u8) -> Option<Self> {
    59	        match value {
    60	            0 => Some(WaypointType::Start),
    61	            1 => Some(WaypointType::Jump),
    62	            2 => Some(WaypointType::NpcGate),
    63	            3 => Some(WaypointType::SmartGate),
    64	            4 => Some(WaypointType::SetDestination),
    65	            _ => None,
    66	        }
    67	    }
