    92	/// Binary header structure for fmap encoding.
    93	///
    94	/// Layout:
    95	/// - Byte 0: Version (u8, must be 1)
    96	/// - Byte 1: Bit width k (u8, 1-30)
    97	/// - Bytes 2-3: Waypoint count (u16 big-endian)
    98	#[allow(dead_code)]
    99	#[derive(Debug, Clone, Copy)]
   100	struct FmapHeader {
   101	    version: u8,
   102	    bit_width: u8,
   103	    count: u16,
   104	}
   105	
   106	/// Helper for writing bits at a time to a byte buffer.
   107	struct BitWriter {
   108	    bytes: Vec<u8>,
   109	    cur: u8,
   110	    bits: usize, // bits currently in cur (0..8)
   111	}
   112	
   113	impl BitWriter {
   114	    fn new() -> Self {
   115	        BitWriter {
   116	            bytes: Vec::new(),
   117	            cur: 0,
   118	            bits: 0,
   119	        }
   120	    }
   121	
   122	    fn write_bits(&mut self, value: u32, bit_count: u8) {
   123	        for i in (0..bit_count).rev() {
   124	            let bit = ((value >> i) & 1) as u8;
   125	            self.cur = (self.cur << 1) | bit;
   126	            self.bits += 1;
   127	            if self.bits == 8 {
   128	                self.bytes.push(self.cur);
   129	                self.cur = 0;
   130	                self.bits = 0;
   131	            }
   132	        }
   133	    }
   134	
   135	    fn finish(mut self) -> Vec<u8> {
   136	        if self.bits > 0 {
   137	            self.cur <<= 8 - self.bits;
   138	            self.bytes.push(self.cur);
   139	        }
   140	        self.bytes
   141	    }
   142	}
   143	
   144	/// Helper for reading bits at a time from a byte buffer.
   145	/// Used in Phase 4 (decoding).
   146	#[allow(dead_code)]
   147	struct BitReader<'a> {
   148	    buf: &'a [u8],
   149	    idx: usize,       // byte index
   150	    cur: u8,          // current byte
   151	    bits_left: usize, // bits remaining in cur (0..8)
   152	}
   153	
   154	#[allow(dead_code)]
   155	impl<'a> BitReader<'a> {
   156	    fn new(buf: &'a [u8]) -> Self {
   157	        BitReader {
   158	            buf,
   159	            idx: 0,
   160	            cur: if !buf.is_empty() { buf[0] } else { 0 },
   161	            bits_left: if !buf.is_empty() { 8 } else { 0 },
   162	        }
   163	    }
   164	
   165	    fn read_bits(&mut self, bit_count: u8) -> Result<u32, Error> {
   166	        let mut v = 0u32;
   167	        for _ in 0..bit_count {
   168	            if self.bits_left == 0 {
   169	                self.idx += 1;
   170	                if self.idx >= self.buf.len() {
   171	                    return Err(Error::FmapTruncatedData {
   172	                        expected: self.idx + 1,
   173	                        actual: self.buf.len(),
   174	                    });
   175	                }
   176	                self.cur = self.buf[self.idx];
   177	                self.bits_left = 8;
   178	            }
   179	            let msb = (self.cur & 0x80) != 0;
   180	            v = (v << 1) | (msb as u32);
   181	            self.cur <<= 1;
   182	            self.bits_left -= 1;
   183	        }
   184	        Ok(v)
   185	    }
   186	}
