   188	/// Calculate the required bit width for encoding a maximum offset.
   189	fn calculate_bit_width(max_offset: u32) -> u8 {
   190	    if max_offset == 0 {
   191	        1
   192	    } else {
   193	        (32 - max_offset.leading_zeros()) as u8
   194	    }
   195	}
