   262	
   263	/// Encode waypoints to an fmap token string.
   264	///
   265	/// # Arguments
   266	/// * `waypoints` - Slice of Waypoint structs to encode
   267	///
   268	/// # Returns
   269	/// * `Ok(FmapToken)` - Token with metadata on success
   270	/// * `Err(Error)` - Encoding error with details
   271	pub fn encode_fmap_token(waypoints: &[Waypoint]) -> Result<FmapToken, Error> {
   272	    let raw = encode_raw_bitpacked(waypoints)?;
   273	
   274	    // Compress with gzip
   275	    let mut encoder = flate2::write::GzEncoder::new(Vec::new(), flate2::Compression::best());
   276	    use std::io::Write;
   277	    encoder
   278	        .write_all(&raw)
   279	        .map_err(|e| Error::FmapCompressionError { source: e })?;
   280	    let compressed = encoder
   281	        .finish()
   282	        .map_err(|e| Error::FmapCompressionError { source: e })?;
   283	
   284	    // Encode to base64url
   285	    let token = to_base64url(&compressed);
   286	
   287	    // Extract header info for metadata
   288	    let version = raw[0];
   289	    let bit_width = raw[1];
   290	
   291	    Ok(FmapToken {
   292	        token,
   293	        waypoint_count: waypoints.len(),
   294	        bit_width,
   295	        version,
